import*as React from"react";const useDetectScrollDirection=()=>{const t=React.useRef(0),c=React.useRef(0);return React.useCallback(e=>{var{scrollTop:e,scrollLeft:r}=e.currentTarget;return e!==c.current?(c.current=e,"vertical"):r!==t.current?(t.current=r,"horizontal"):null},[])};export{useDetectScrollDirection};